-- Program: Minimal Noise Workout
-- Category: YouTube-Style Home Programs -> home_workout
-- Priority: Med
-- Durations: [2, 4, 8], Sessions: [3, 4]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Minimal Noise Workout',
    'Silent strength training with slow tempo and isometric holds - no jumping',
    'home_workout',
    'all_levels',
    8,
    4,
    'custom',
    ARRAY['Increase maximal strength', 'Progressive overload', 'Build functional strength', 'Improve body control']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Minimal Noise Workout - 2w 3x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    2,
    'Minimal Noise Workout - 2w 3x/wk',
    'home_workout',
    3,
    60,
    ARRAY['Increase maximal strength', 'Progressive overload', 'Build functional strength', 'Improve body control']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Minimal Noise Workout'
ON CONFLICT DO NOTHING;

